INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0604756N$$, 2026, $$This program element provides funding for the development of systems that fulfill a portion of the third phase of the Ship Self Defense: Engage Hard Kill. Development in
this line will focus on hard kill capabilities in which missiles and other munitions are used to intercept incoming Anti-Ship Cruise Missiles (ASCM), as well as a Surface-to
Surface Strike weapon system. System improvements are being addressed via Rolling Airframe Missile (RAM) (0167), NATO SEASPARROW Missile System (NSSMS)
(0173), Over-The-Horizon (OTH) missile (2070), Afloat Counter-Unmanned Aerial Systems (C-UAS) (2077), and MK-15 Close-In Weapon System (CIWS) (9081).$$, $$The MK 15 MOD 40 Close in Weapon System (CIWS) RAM Defense Capability (CRDC) configuration is fielded aboard Nimitz Class Carriers (CVN). It is a fast reaction,
rapid fire, computer-controlled radar system that employs the Rolling Airframe Missile (RAM) as an effector for Anti-Ship Missile (ASM) defense. The MK 15 MOD 40
CIWS (CRDC) configuration was fielded in FY 2020, limited to the RAM BLK 2 missile variant. The purpose of this project is to develop and integrate the latest RAM
missile variant (BLK 2B) into the MK 15 MOD 40 baseline. The RAM Block 2B missile defends against highly maneuverable Anti-Ship Cruise Missile (ASCM) threats and
emerging complex raid attacks utilizing an advanced infrared (IR) seeker and Missile-to-Missile Link (MML) while maintaining all the proven capabilities of previous RAM
variants (BLK 2): accurate terminal guidance, proven lethality, and post-launch fire and forget capability.

 Without this effort the Nimitz class carriers will be unable to utilize the latest and most capable RAM Block 2B missile which entered production in FY 2023.

