INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0605457A$$, 2027, $$This funding line is directly aligned to the U.S. Army Air and Missile Defense (AMD) Modernization Priority. The Army Integrated Air and Missile Defense (AIAMD)
program is a designated Major Defense Acquisition Program (MDAP), a critical component of the Army's AMD strategy, and is a top AMD Cross Functional Team
modernization priority program.

 Remote Interceptor Guidance 360 (RIG-360) is a software-defined, X-band missile communications device that provides full hemispherical, 360-degree in-flight
 communications with IAMD Composite Task Force interceptors including the PATRIOT Advanced Capability 3 (PAC-3) family of interceptors. The RIG-360 adds
 capability to the AIAMD architecture by unlocking the full kinematic potential of the PAC-3 family of interceptors providing full 360-degree coverage against attacking
 non-ballistic threats. The system expands the Warfighter's area of control and increases AMD effectiveness. RIG's 360-degree engagement capability leverages
 sensors integrated within the IBCS architecture and integrates an interceptor datalink device as a network component advancing IAMD goals of pairing any sensor with
 best shooter.

 The RIG-360 consists of two Major End Items, the Control Assembly and Array Assembly. The Control Assembly, in a rack mounted case, is the control node for the
 Array Assembly and serves as the Adaptation Kit (A-Kit) to the Integrated Fire Control Network. The rack mounted case provides outer ruggedness to environmental
 conditions with internal shock isolation, while allowing easy interchange of power supplies, server components, or other components as required within an industry
 standard rack assembly. The RIG-360 Array Assembly is a mast-mounted, X-band array of antennas that transmit and receive the interceptor radio frequency PAC-3
 missile communication waveforms.

 FY 2027 Funds in the amount of $39.030 million supports completion of RIG 360 development and conduct of IOTE in support of a FY 2027 Milestone C decision.$$, $$This funding line is directly aligned to the U.S. Army Air and Missile Defense (AMD) Modernization Priority. The Army Integrated Air and Missile Defense (AIAMD)
